import json
import hashlib

def load_batch(path):
    with open(path) as f:
        return json.load(f)

def find_pattern(batches, pattern_id):
    results = []
    for batch_name, batch in batches.items():
        for record in batch['outputs']:
            if record.get('pattern_id') == pattern_id:
                results.append({
                    'batch': batch_name,
                    'timestamp': record['timestamp'],
                    'input_hash': record.get('input_hash', '[NULL]')
                })
    return results

